# factorial.tcl

# This script calculates the factorial of a positive integer using recursion.
# It prompts the user to enter a positive integer and handles invalid input.

# Function to calculate factorial recursively
proc factorial {n} {
    # Base case: factorial of 0 is 1
    if {$n == 0} {
        return 1
    } else {
        # Recursive case: n! = n * (n-1)!
        return [expr $n * [factorial [expr $n - 1]]]
    }
}

# Function to get user input and validate it as a positive integer
proc getUserInput {} {
    set input ""
    while {1} {
        puts "Please enter a positive integer:"
        set input [gets stdin]

        # Check if the input is a valid integer
        if {[string is integer -strict $input]} {
            # Check if the integer is positive
            if {$input >= 0} {
                return $input
            } else {
                puts "The number must be positive."
            }
        } else {
            puts "Invalid input. Please enter an integer."
        }
    }
}

# Main script
proc main {} {
    set number [getUserInput]
    set result [factorial $number]
    puts "The factorial of $number is $result."
}

# Call the main function to start the script
main
