use std::fs::File;
use std::io::{self, Read, Write};

fn main() -> io::Result<()> {
    // Define the input and output file paths
    let input_file_path = "input.bin";
    let output_file_path = "output.bin";

    // Open the input file in read-only mode
    let mut input_file = File::open(input_file_path)?;

    // Open the output file in write mode
    let mut output_file = File::create(output_file_path)?;

    // Buffer to hold chunks of data
    let mut buffer: [u8; 1024] = [0; 1024];

    // Read data from the input file in chunks
    let mut total_bytes_read = 0;
    loop {
        let bytes_read = input_file.read(&mut buffer)?;
        if bytes_read == 0 {
            break;
        }

        // Write the length of the chunk as a 4-byte integer (big-endian)
        output_file.write(&bytes_read.to_be_bytes())?;
        output_file.write_all(&buffer[..bytes_read])?;
        total_bytes_read += bytes_read;
    }

    println!("Total bytes read: {}", total_bytes_read);

    Ok(())
}
```

### Explanation:

1. **Reading the Binary File:**
   - `input_file_path` is the path to the binary file from which we read the data.
   - `File::open` is used to open the file in read-only mode.
   - `read` method is used to read data in chunks of 1024 bytes into the `buffer`.

2. **Writing to the Output File:**
   - `output_file_path` is the path to the new file where we will write the formatted data.
   - `File::create` is used to create the output file in write mode.
